    if not digits:
        return 0

    # Sort digits in descending order
    digits.sort(reverse=True)

    # If k is 0, return the number formed by all digits
    if k == 0:
        return int(''.join(map(str, digits)))

    # If k is greater than the number of digits, we can only use all digits
    if k >= len(digits):
        return int(''.join(map(str, digits)))

    # We need to remove k digits to form the largest number
    # Use a monotonic stack approach
    result = []
    for digit in digits:
        while k > 0 and result and result[-1] < digit:
            result.pop()
