    if start_row < 0 or start_row >= len(triangle) or start_col < 0 or start_col > start_row:
        return 0

    rows = len(triangle)

    # Dynamic programming table
    dp = [[0] * (rows + 1) for _ in range(rows + 1)]

    # Fill the dp table from bottom to top
    for i in range(rows - 1, -1, -1):
        for j in range(i + 1):
            if i == rows - 1:
                dp[i][j] = triangle[i][j]
